export type MessageKey = keyof typeof messages

export function useMessages() {
  const intl = useIntl()
  return {
    t: (key: MessageKey, values?: Record<string, PrimitiveType>) => intl.formatMessage(messages[key], values),
    formatDate: (value: string | number | Date, options?: Intl.DateTimeFormatOptions) => intl.formatDate(value, options),
    formatTime: (value: string | number | Date, options?: Intl.DateTimeFormatOptions) => intl.formatTime(value, options),
    formatNumber: (value: number, options?: Parameters<typeof intl.formatNumber>[1]) => intl.formatNumber(value, options),
  }
}
